     1→// Phase 5: TypeChecker - 정적 타입 검증
     2→
     3→import { Expr, Stmt, Program, CapabilityAnnotation } from "./ast"
     4→import {
     5→  Type,
     6→  PrimitiveType,
     7→  TypeCheckError,
     8→  TypeCheckResult,
     9→  typesCompatible,
    10→  typeToString,
    11→  getOperationResultType,
    12→  inferTypeFromValue,
    13→  BUILTIN_TYPES,
    14→  Capability,
    15→  CapabilityKind,
    16→} from "./type-system"
    17→
    18→/**
    19→ * TypeChecker: AST 기반 정적 타입 검증
    20→ */
    21→export class TypeChecker {
    22→  private env: Map<string, Type> = new Map()
    23→  private functionTypes: Map<string, Type> = new Map()
    24→  private errors: TypeCheckError[] = []
    25→  private currentFunctionReturnTypes: Type[] = []
    26→  private currentCapabilities: Capability[] = []
    27→
    28→  // Phase 6: Built-in 함수 required capability
    29→  private readonly BUILTIN_REQUIRED_CAPABILITIES: Map<string, CapabilityKind> = new Map([
    30→    ["file_read", "read_file"],
    31→    ["file_write", "write_file"],
    32→    ["http_request", "network"],
    33→    ["http_get", "network"],
    34→    ["process_spawn", "spawn_process"],
    35→    ["eval", "execute_code"],
    36→  ])
    37→
    38→  /**
    39→   * 전체 프로그램 타입 검사
    40→   */
    41→  public check(program: Program): TypeCheckResult {
    42→    this.errors = []
    43→    this.env.clear()
    44→    this.functionTypes.clear()
    45→
    46→    // First pass: 함수 정의 수집
    47→    for (const stmt of program.stmts) {
    48→      if (stmt.kind === "fn") {
    49→        this.registerFunctionType(stmt)
    50→      }
    51→    }
    52→
    53→    // Second pass: 함수 본문 및 다른 명령문 검사
    54→    for (const stmt of program.stmts) {
    55→      this.checkStmt(stmt)
    56→    }
    57→
    58→    return {
    59→      success: this.errors.length === 0,
    60→      errors: this.errors,
    61→      types: new Map(this.env),
    62→    }
    63→  }
    64→
    65→  /**
    66→   * 수집된 return 타입들로부터 함수의 반환 타입 추론
    67→   */
    68→  private inferReturnType(types: Type[]): Type {
    69→    if (types.length === 0) return BUILTIN_TYPES.UNKNOWN
    70→    const first = types[0]
    71→    if (types.every(t => JSON.stringify(t) === JSON.stringify(first)))
    72→      return first
    73→    return BUILTIN_TYPES.UNKNOWN
    74→  }
    75→
    76→  /**
    77→   * 함수 타입 등록
    78→   */
    79→  private registerFunctionType(stmt: Stmt): void {
    80→    if (stmt.kind === "fn") {
    81→      const fnStmt = stmt as any
    82→      const paramTypes: Type[] = (fnStmt.params || []).map(() => ({
    83→        kind: "primitive" as const,
    84→        type: PrimitiveType.UNKNOWN,
    85→      }))
    86→
    87→      const returnType: Type = {
    88→        kind: "primitive",
    89→        type: PrimitiveType.UNKNOWN,
    90→      }
    91→
    92→      // Phase 6: annotations → capabilities 변환
    93→      const capabilities: Capability[] = (fnStmt.annotations || [])
    94→        .filter((a: any) => a.kind === "allow")
    95→        .map((a: any) => ({ cap: a.cap, arg: a.arg }))
    96→
    97→      const fnType: Type = {
    98→        kind: "fn",
    99→        paramTypes,
   100→        returnType,
   101→        capabilities,
   102→      }
   103→
   104→      this.functionTypes.set(fnStmt.name, fnType)
   105→    }
   106→  }
   107→
   108→  /**
   109→   * 명령문 타입 검사
   110→   */
   111→  private checkStmt(stmt: Stmt): void {
   112→    switch (stmt.kind) {
   113→      case "print": {
   114→        const printStmt = stmt as any
   115→        this.checkExpr(printStmt.expr)
   116→        break
   117→      }
   118→
   119→      case "expr": {
   120→        const exprStmt = stmt as any
   121→        this.checkExpr(exprStmt.expr)
   122→        break
   123→      }
   124→
   125→      case "let": {
   126→        const letStmt = stmt as any
   127→        if (letStmt.init) {
   128→          const valueType = this.checkExpr(letStmt.init)
   129→          this.env.set(letStmt.name, valueType)
   130→        } else {
   131→          this.env.set(letStmt.name, BUILTIN_TYPES.UNKNOWN)
   132→        }
   133→        break
   134→      }
   135→
   136→      case "fn": {
   137→        const fnStmt = stmt as any
   138→        const savedEnv = new Map(this.env)
   139→        const savedReturnTypes = this.currentFunctionReturnTypes
   140→        const savedCapabilities = this.currentCapabilities
   141→
   142→        // Phase 6: 현재 함수의 선언 capability로 컨텍스트 설정
   143→        const fnType = this.functionTypes.get(fnStmt.name)
   144→        this.currentCapabilities = fnType?.kind === "fn"
   145→          ? (fnType.capabilities ?? [])
   146→          : []
   147→
   148→        this.currentFunctionReturnTypes = []
   149→
   150→        // 파라미터를 환경에 추가
   151→        for (const param of fnStmt.params || []) {
   152→          this.env.set(param, {
   153→            kind: "primitive",
   154→            type: PrimitiveType.UNKNOWN,
   155→          })
   156→        }
   157→
   158→        // 함수 본문 검사
   159→        for (const s of fnStmt.body || []) {
   160→          this.checkStmt(s)
   161→        }
   162→
   163→        // return 타입 추론 후 functionTypes 갱신
   164→        const inferredReturn = this.inferReturnType(
   165→          this.currentFunctionReturnTypes
   166→        )
   167→        const existingFnType = this.functionTypes.get(fnStmt.name)
   168→        if (existingFnType && existingFnType.kind === "fn") {
   169→          this.functionTypes.set(fnStmt.name, {
   170→            kind: "fn",
   171→            paramTypes: existingFnType.paramTypes,
   172→            returnType: inferredReturn,
   173→            capabilities: existingFnType.capabilities, // Phase 6: 보존
   174→          })
   175→        }
   176→
   177→        this.currentCapabilities = savedCapabilities
   178→        this.currentFunctionReturnTypes = savedReturnTypes
   179→        this.env = savedEnv
   180→        break
   181→      }
   182→
   183→      case "if": {
   184→        const ifStmt = stmt as any
   185→        this.checkExpr(ifStmt.cond)
   186→        for (const s of ifStmt.then || []) {
   187→          this.checkStmt(s)
   188→        }
   189→        if (ifStmt.else) {
   190→          for (const s of ifStmt.else) {
   191→            this.checkStmt(s)
   192→          }
   193→        }
   194→        break
   195→      }
   196→
   197→      case "for": {
   198→        const forStmt = stmt as any
   199→        this.checkExpr(forStmt.iter)
   200→        // 루프 변수를 환경에 추가
   201→        this.env.set(forStmt.name, BUILTIN_TYPES.UNKNOWN)
   202→        for (const s of forStmt.body || []) {
   203→          this.checkStmt(s)
   204→        }
   205→        break
   206→      }
   207→
   208→      case "while": {
   209→        const whileStmt = stmt as any
   210→        this.checkExpr(whileStmt.cond)
   211→        for (const s of whileStmt.body || []) {
   212→          this.checkStmt(s)
   213→        }
   214→        break
   215→      }
   216→
   217→      case "return": {
   218→        const returnStmt = stmt as any
   219→        if (returnStmt.value) {
   220→          const retType = this.checkExpr(returnStmt.value)
   221→          this.currentFunctionReturnTypes.push(retType)
   222→        }
   223→        break
   224→      }
   225→
   226→      case "block": {
   227→        const blockStmt = stmt as any
   228→        for (const s of blockStmt.body || []) {
   229→          this.checkStmt(s)
   230→        }
   231→        break
   232→      }
   233→
   234→      case "try": {
   235→        const tryStmt = stmt as any
   236→        for (const s of tryStmt.body || []) {
   237→          this.checkStmt(s)
   238→        }
   239→        if (tryStmt.catchVar) {
   240→          this.env.set(tryStmt.catchVar, BUILTIN_TYPES.UNKNOWN)
   241→        }
   242→        for (const s of tryStmt.catchBody || []) {
   243→          this.checkStmt(s)
   244→        }
   245→        for (const s of tryStmt.finallyBody || []) {
   246→          this.checkStmt(s)
   247→        }
   248→        break
   249→      }
   250→
   251→      case "throw": {
   252→        const throwStmt = stmt as any
   253→        this.checkExpr(throwStmt.expr)
   254→        break
   255→      }
   256→
   257→      case "if-let": {
   258→        const ifLetStmt = stmt as any
   259→        this.checkExpr(ifLetStmt.value)
   260→        // 패턴 바인딩
   261→        if (ifLetStmt.pattern.kind === "ident") {
   262→          this.env.set(ifLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   263→        }
   264→        for (const s of ifLetStmt.body || []) {
   265→          this.checkStmt(s)
   266→        }
   267→        if (ifLetStmt.else) {
   268→          for (const s of ifLetStmt.else) {
   269→            this.checkStmt(s)
   270→          }
   271→        }
   272→        break
   273→      }
   274→
   275→      case "while-let": {
   276→        const whileLetStmt = stmt as any
   277→        this.checkExpr(whileLetStmt.value)
   278→        if (whileLetStmt.pattern.kind === "ident") {
   279→          this.env.set(whileLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   280→        }
   281→        for (const s of whileLetStmt.body || []) {
   282→          this.checkStmt(s)
   283→        }
   284→        break
   285→      }
   286→
   287→      case "match": {
   288→        const matchStmt = stmt as any
   289→        this.checkExpr(matchStmt.subject)
   290→        for (const arm of matchStmt.arms || []) {
   291→          if (arm.pattern) {
   292→            this.checkExpr(arm.pattern)
   293→          }
   294→          if (arm.guard) {
   295→            this.checkExpr(arm.guard)
   296→          }
   297→          for (const s of arm.body || []) {
   298→            this.checkStmt(s)
   299→          }
   300→        }
   301→        break
   302→      }
   303→    }
   304→  }
   305→
   306→  /**
   307→   * 표현식 타입 검사
   308→   */
   309→  public checkExpr(expr: Expr): Type {
   310→    switch (expr.kind) {
   311→      case "number":
   312→        return { kind: "primitive", type: PrimitiveType.NUM }
   313→
   314→      case "string":
   315→        return { kind: "primitive", type: PrimitiveType.STR }
   316→
   317→      case "bool":
   318→        return { kind: "primitive", type: PrimitiveType.BOOL }
   319→
   320→      case "null":
   321→        return { kind: "primitive", type: PrimitiveType.NULL }
   322→
   323→      case "ident": {
   324→        const identExpr = expr as any
   325→        const type = this.env.get(identExpr.name)
   326→        if (!type) {
   327→          this.addError(
   328→            `Undefined variable '${identExpr.name}'`,
   329→            undefined,
   330→            undefined
   331→          )
   332→          return BUILTIN_TYPES.UNKNOWN
   333→        }
   334→        return type
   335→      }
   336→
   337→      case "assign": {
   338→        const assignExpr = expr as any
   339→        const valueType = this.checkExpr(assignExpr.value)
   340→
   341→        // target이 ident인 경우 할당
   342→        if (assignExpr.target.kind === "ident") {
   343→          this.env.set(assignExpr.target.name, valueType)
   344→        }
   345→        return valueType
   346→      }
   347→
   348→      case "binary": {
   349→        const binExpr = expr as any
   350→        const leftType = this.checkExpr(binExpr.left)
   351→        const rightType = this.checkExpr(binExpr.right)
   352→
   353→        // 타입 호환성 검사
   354→        const resultType = getOperationResultType(
   355→          binExpr.op,
   356→          leftType,
   357→          rightType
   358→        )
   359→
   360→        // Add 연산 검증
   361→        if (binExpr.op === "+" || binExpr.op === "Add") {
   362→          if (leftType.kind === "primitive" && rightType.kind === "primitive") {
   363→            const left = leftType.type
   364→            const right = rightType.type
   365→
   366→            if (
   367→              !(
   368→                (left === PrimitiveType.NUM && right === PrimitiveType.NUM) ||
   369→                (left === PrimitiveType.STR || right === PrimitiveType.STR) ||
   370→                (left === PrimitiveType.UNKNOWN ||
   371→                  right === PrimitiveType.UNKNOWN)
   372→              )
   373→            ) {
   374→              this.addError(
   375→                `Cannot add ${typeToString(leftType)} and ${typeToString(rightType)}`,
   376→                undefined,
   377→                undefined,
   378→                undefined,
   379→                leftType,
   380→                rightType
   381→              )
   382→            }
   383→          }
   384→        }
   385→
   386→        return resultType
   387→      }
   388→
   389→      case "unary": {
   390→        const unaryExpr = expr as any
   391→        const operandType = this.checkExpr(unaryExpr.expr)
   392→
   393→        if (unaryExpr.op === "!") {
   394→          if (
   395→            operandType.kind !== "primitive" ||
   396→            operandType.type !== PrimitiveType.BOOL
   397→          ) {
   398→            this.addError(
   399→              `Cannot apply ! to ${typeToString(operandType)}`,
   400→              undefined,
   401→              undefined
   402→            )
   403→          }
   404→          return BUILTIN_TYPES.BOOL
   405→        }
   406→
   407→        if (unaryExpr.op === "-") {
   408→          if (
   409→            operandType.kind !== "primitive" ||
   410→            operandType.type !== PrimitiveType.NUM
   411→          ) {
   412→            this.addError(
   413→              `Cannot negate ${typeToString(operandType)}`,
   414→              undefined,
   415→              undefined
   416→            )
   417→          }
   418→          return BUILTIN_TYPES.NUM
   419→        }
   420→
   421→        return operandType
   422→      }
   423→
   424→      case "call": {
   425→        const callExpr = expr as any
   426→
   427→        // callee에서 함수 이름 추출
   428→        let fnName = ""
   429→        if (callExpr.callee.kind === "ident") {
   430→          fnName = callExpr.callee.name
   431→        }
   432→
   433→        // Phase 6: Built-in 함수 required capability 검사
   434→        const builtinRequired = this.BUILTIN_REQUIRED_CAPABILITIES.get(fnName)
   435→        if (builtinRequired) {
   436→          const callerHas = this.currentCapabilities.some(c => c.cap === builtinRequired)
   437→          if (!callerHas) {
   438→            this.addError(
   439→              `'${fnName}' requires capability '${builtinRequired}', not declared`,
   440→              undefined,
   441→              undefined
   442→            )
   443→          }
   444→        }
   445→
   446→        const fnType = this.functionTypes.get(fnName)
   447→
   448→        if (!fnType) {
   449→          this.addError(
   450→            `Undefined function '${fnName}'`,
   451→            undefined,
   452→            undefined
   453→          )
   454→          return BUILTIN_TYPES.UNKNOWN
   455→        }
   456→
   457→        if (fnType.kind === "fn") {
   458→          // 인자 개수 확인
   459→          if ((callExpr.args || []).length !== fnType.paramTypes.length) {
   460→            this.addError(
   461→              `Function '${fnName}' expects ${fnType.paramTypes.length} arguments, got ${(callExpr.args || []).length}`,
   462→              undefined,
   463→              undefined
   464→            )
   465→          }
   466→
   467→          // 인자 타입 검사
   468→          for (let i = 0; i < (callExpr.args || []).length; i++) {
   469→            const argType = this.checkExpr(callExpr.args[i])
   470→            const paramType = fnType.paramTypes[i] || BUILTIN_TYPES.UNKNOWN
   471→
   472→            if (!typesCompatible(argType, paramType)) {
   473→              this.addError(
   474→                `Argument ${i} of '${fnName}': expected ${typeToString(paramType)}, got ${typeToString(argType)}`,
   475→                undefined,
   476→                undefined,
   477→                undefined,
   478→                paramType,
   479→                argType
   480→              )
   481→            }
   482→          }
   483→
   484→          // Phase 6: Capability Propagation 검증
   485→          // Strict: callee.capabilities ⊆ caller.capabilities
   486→          if (fnType.capabilities && fnType.capabilities.length > 0) {
   487→            for (const required of fnType.capabilities) {
   488→              const callerHas = this.currentCapabilities.some(
   489→                c => c.cap === required.cap && this.capabilityCovers(c, required)
   490→              )
   491→              if (!callerHas) {
   492→                this.addError(
   493→                  `Call to '${fnName}' requires capability '${required.cap}' ` +
   494→                  `${required.arg ? `(${required.arg})` : ""}, ` +
   495→                  `but caller does not declare it`,
   496→                  undefined,
   497→                  undefined
   498→                )
   499→              }
   500→            }
   501→          }
   502→
   503→          return fnType.returnType
   504→        }
   505→
   506→        return BUILTIN_TYPES.UNKNOWN
   507→      }
   508→
   509→      case "array": {
   510→        const arrayExpr = expr as any
   511→        if ((arrayExpr.elements || []).length === 0) {
   512→          return {
   513→            kind: "array",
   514→            elementType: BUILTIN_TYPES.UNKNOWN,
   515→          }
   516→        }
   517→
   518→        const elementTypes = (arrayExpr.elements || []).map((e: any) =>
   519→          this.checkExpr(e)
   520→        )
   521→
   522→        // 모든 요소 타입이 같은지 확인
   523→        const firstType = elementTypes[0]
   524→        for (let i = 1; i < elementTypes.length; i++) {
   525→          if (!typesCompatible(elementTypes[i], firstType)) {
   526→            this.addError(
   527→              `Array elements have inconsistent types: ${typeToString(firstType)} and ${typeToString(elementTypes[i])}`,
   528→              undefined,
   529→              undefined
   530→            )
   531→          }
   532→        }
   533→
   534→        return {
   535→          kind: "array",
   536→          elementType: firstType,
   537→        }
   538→      }
   539→
   540→      case "index": {
   541→        const indexExpr = expr as any
   542→        const objectType = this.checkExpr(indexExpr.object)
   543→        this.checkExpr(indexExpr.index)
   544→
   545→        if (objectType.kind === "array") {
   546→          return objectType.elementType
   547→        }
   548→        return BUILTIN_TYPES.UNKNOWN
   549→      }
   550→
   551→      case "member": {
   552→        const memberExpr = expr as any
   553→        const objectType = this.checkExpr(memberExpr.object)
   554→
   555→        if (objectType.kind === "object") {
   556→          const propType = objectType.properties.get(memberExpr.property)
   557→          return propType || BUILTIN_TYPES.UNKNOWN
   558→        }
   559→        return BUILTIN_TYPES.UNKNOWN
   560→      }
   561→
   562→      case "object": {
   563→        const objExpr = expr as any
   564→        const properties = new Map<string, Type>()
   565→
   566→        for (const entry of objExpr.entries || []) {
   567→          properties.set(entry.key, this.checkExpr(entry.value))
   568→        }
   569→
   570→        return {
   571→          kind: "object",
   572→          properties,
   573→        }
   574→      }
   575→
   576→      case "fn": {
   577→        const fnExpr = expr as any
   578→        const savedEnv = new Map(this.env)
   579→        const savedReturnTypes = this.currentFunctionReturnTypes
   580→
   581→        this.currentFunctionReturnTypes = []
   582→
   583→        // 파라미터를 환경에 추가
   584→        for (const param of fnExpr.params || []) {
   585→          this.env.set(param, {
   586→            kind: "primitive",
   587→            type: PrimitiveType.UNKNOWN,
   588→          })
   589→        }
   590→
   591→        // 함수 본문 검사
   592→        for (const stmt of fnExpr.body || []) {
   593→          this.checkStmt(stmt)
   594→        }
   595→
   596→        const inferredReturn = this.inferReturnType(
   597→          this.currentFunctionReturnTypes
   598→        )
   599→        const paramTypes: Type[] = (fnExpr.params || []).map(() => ({
   600→          kind: "primitive" as const,
   601→          type: PrimitiveType.UNKNOWN,
   602→        }))
   603→
   604→        this.currentFunctionReturnTypes = savedReturnTypes
   605→        this.env = savedEnv
   606→
   607→        return {
   608→          kind: "fn",
   609→          paramTypes,
   610→          returnType: inferredReturn,
   611→        }
   612→      }
   613→
   614→      case "ternary": {
   615→        const ternaryExpr = expr as any
   616→        this.checkExpr(ternaryExpr.cond)
   617→        const thenType = this.checkExpr(ternaryExpr.then)
   618→        const elseType = this.checkExpr(ternaryExpr.else)
   619→
   620→        // then과 else 타입이 호환 가능해야 함
   621→        if (!typesCompatible(thenType, elseType)) {
   622→          this.addError(
   623→            `Ternary branch types incompatible: ${typeToString(thenType)} vs ${typeToString(elseType)}`,
   624→            undefined,
   625→            undefined
   626→          )
   627→        }
   628→
   629→        return thenType
   630→      }
   631→
   632→      case "if": {
   633→        const ifExpr = expr as any
   634→        this.checkExpr(ifExpr.cond)
   635→        for (const s of ifExpr.then || []) {
   636→          this.checkStmt(s)
   637→        }
   638→        for (const s of ifExpr.else || []) {
   639→          this.checkStmt(s)
   640→        }
   641→        return BUILTIN_TYPES.UNKNOWN
   642→      }
   643→
   644→      case "match": {
   645→        const matchExpr = expr as any
   646→        this.checkExpr(matchExpr.subject)
   647→        for (const arm of matchExpr.arms || []) {
   648→          if (arm.pattern) {
   649→            this.checkExpr(arm.pattern)
   650→          }
   651→          if (arm.guard) {
   652→            this.checkExpr(arm.guard)
   653→          }
   654→          for (const s of arm.body || []) {
   655→            this.checkStmt(s)
   656→          }
   657→        }
   658→        return BUILTIN_TYPES.UNKNOWN
   659→      }
   660→
   661→      default:
   662→        return BUILTIN_TYPES.UNKNOWN
   663→    }
   664→  }
   665→
   666→  /**
   667→   * 오류 추가
   668→   */
   669→  private addError(
   670→    message: string,
   671→    line?: number,
   672→    column?: number,
   673→    variable?: string,
   674→    expected?: Type,
   675→    actual?: Type
   676→  ): void {
   677→    this.errors.push({
   678→      message,
   679→      line,
   680→      column,
   681→      variable,
   682→      expected,
   683→      actual,
   684→    })
   685→  }
   686→
   687→  /**
   688→   * 환경 조회
   689→   */
   690→  public getEnv(): Map<string, Type> {
   691→    return new Map(this.env)
   692→  }
   693→
   694→  /**
   695→   * 함수 타입 조회
   696→   */
   697→  public getFunctionType(name: string): Type | undefined {
   698→    return this.functionTypes.get(name)
   699→  }
   700→
   701→  /**
   702→   * 오류 개수
   703→   */
   704→  public getErrorCount(): number {
   705→    return this.errors.length
   706→  }
   707→
   708→  /**
   709→   * 오류 목록
   710→   */
   711→  public getErrors(): TypeCheckError[] {
   712→    return [...this.errors]
   713→  }
   714→
   715→  /**
   716→   * Phase 6: Capability 헬퍼 함수들
   717→   */
   718→  private capabilityCovers(caller: Capability, callee: Capability): boolean {
   719→    if (caller.cap !== callee.cap) return false
   720→    if (!callee.arg) return true // callee가 경로 무관하면 OK
   721→    if (!caller.arg) return false
   722→
   723→    // Path: /tmp → /tmp/file.txt OK, /tmp → /etc NG
   724→    if (caller.cap === "read_file" || caller.cap === "write_file") {
   725→      return this.pathIsUnder(callee.arg, caller.arg)
   726→    }
   727→
   728→    // Network: api.openai.com → api.openai.com OK, *.openai.com → sub.openai.com OK
   729→    if (caller.cap === "network") {
   730→      return this.hostMatches(callee.arg, caller.arg)
   731→    }
   732→
   733→    return caller.arg === callee.arg
   734→  }
   735→
   736→  private pathIsUnder(target: string, allowedPrefix: string): boolean {
   737→    // ".." 즉시 거부
   738→    if (target.includes("..")) return false
   739→    const normalized = target.replace(/\/+/g, "/").replace(/\/$/, "")
   740→    const prefix = allowedPrefix.replace(/\/+/g, "/").replace(/\/$/, "")
   741→    return normalized === prefix || normalized.startsWith(prefix + "/")
   742→  }
   743→
   744→  private hostMatches(target: string, pattern: string): boolean {
   745→    if (pattern === target) return true
   746→    if (pattern.startsWith("*.")) {
   747→      const base = pattern.slice(2)
   748→      return (
   749→        target.endsWith("." + base) &&
   750→        !target.slice(0, -base.length - 1).includes(".")
   751→      )
   752→    }
   753→    return false
   754→  }
   755→}
