     1→// FreeLang v6: Bytecode Compiler
     2→
     3→import { Expr, Stmt, Program, MatchArm } from "./ast";
     4→
     5→export enum Op {
     6→  Const, Pop, Dup,
     7→  Add, Sub, Mul, Div, Mod, Neg,
     8→  Eq, Neq, Lt, Gt, Lte, Gte,
     9→  And, Or, Not,
    10→  Jump, JumpIfFalse, JumpIfTrue,
    11→  Load, Store, LoadGlobal, StoreGlobal,
    12→  Call, Return, Builtin,
    13→  NewArray, Index, SetIndex,
    14→  NewObject, GetProp, SetProp,
    15→  NewClosure, LoadFree, StoreFree,
    16→  Print, Println,
    17→  TryBegin, TryEnd, Throw,
    18→  Iter, IterNext, IterDone,
    19→  AddrOf, Deref,  // v5.9.1: Pointer operators
    20→  // Phase 4: Unsafe 격리 레이어
    21→  Malloc, Free, Realloc,
    22→  UnsafeRead, UnsafeWrite,
    23→  UnsafeBegin, UnsafeEnd,
    24→  Halt,
    25→  // Phase 5.5: Typed Arithmetic Op (런타임 타입 체크 제거)
    26→  AddNum, SubNum, MulNum, DivNum, ModNum,  // Typed arithmetic
    27→  AddStr,                                   // String concatenation (typed)
    28→  EqNum, LtNum, GtNum, LteNum, GteNum,     // Typed comparison
    29→}
    30→
    31→export type Value =
    32→  | { tag: "num"; val: number }
    33→  | { tag: "str"; val: string }
    34→  | { tag: "bool"; val: boolean }
    35→  | { tag: "null" }
    36→  | { tag: "array"; val: Value[] }
    37→  | { tag: "object"; val: Map<string, Value> }
    38→  | { tag: "fn"; name: string; arity: number; addr: number; freeVars: Value[]; capabilities?: Array<{cap: string; arg?: string}>; resourceLimits?: Record<string, number> }
    39→  | { tag: "builtin"; name: string }
    40→  | { tag: "iter"; val: Value[]; idx: number }
    41→  | { tag: "ptr"; addr: number; target?: Value }; // Pointer type (v5.9.1) - STEP 1: target is optional for HeapManager
    42→
    43→export type Chunk = {
    44→  code: number[];
    45→  constants: Value[];
    46→  lines: number[];
    47→};
    48→
    49→type Local = { name: string; depth: number };
    50→type Upvalue = { name: string; isLocal: boolean; index: number };
    51→type CompilerScope = {
    52→  locals: Local[];
    53→  depth: number;
    54→  upvalues: Upvalue[];
    55→};
    56→
    57→type LoopInfo = { startAddr: number; breakPatches: number[] };
    58→
    59→// Phase 5.5: typeEnv는 TypeChecker가 생성한 Map<string, Type>
    60→export function compile(program: Program, typeEnv?: Map<string, any>): Chunk {
    61→  const chunk: Chunk = { code: [], constants: [], lines: [] };
    62→  const scopes: CompilerScope[] = [{ locals: [], depth: 0, upvalues: [] }];
    63→  const globals = new Set<string>();
    64→  const loopStack: LoopInfo[] = [];
    65→  const finallyStack: Stmt[][] = [];
    66→  const constCache = new Map<string, number>(); // Phase 5.4: 상수 중복 제거
    67→
    68→  // Phase 5.5: 표현식의 타입 추론 (기본 추론만, 복잡한 식은 UNKNOWN)
    69→  function inferExprType(expr: Expr): string | null {
    70→    if (expr.kind === "number") return "num";
    71→    if (expr.kind === "string") return "str";
    72→    if (expr.kind === "bool") return "bool";
    73→    if (expr.kind === "ident" && typeEnv) {
    74→      const t = typeEnv.get(expr.name);
    75→      if (t?.kind === "primitive") return (t as any).type;
    76→    }
    77→    return null; // UNKNOWN → generic fallback
    78→  }
    79→
    80→  function emit(op: Op, line = 0) { chunk.code.push(op); chunk.lines.push(line); }
    81→  function emitArg(op: Op, arg: number, line = 0) { emit(op, line); chunk.code.push(arg); chunk.lines.push(line); }
    82→  function addConst(val: Value): number {
    83→    // Phase 5.4: 상수 중복 제거 - 같은 값이면 기존 인덱스 반환
    84→    const key = JSON.stringify(val);
    85→    const existing = constCache.get(key);
    86→    if (existing !== undefined) return existing;
    87→    const idx = chunk.constants.length;
    88→    chunk.constants.push(val);
    89→    constCache.set(key, idx);
    90→    return idx;
    91→  }
    92→  function currentPos(): number { return chunk.code.length; }
    93→  function patchJump(pos: number) { chunk.code[pos + 1] = currentPos(); }
    94→
    95→  function scope(): CompilerScope { return scopes[scopes.length - 1]; }
    96→
    97→  function resolveLocal(name: string): number {
    98→    const locals = scope().locals;
    99→    for (let i = locals.length - 1; i >= 0; i--) {
   100→      if (locals[i].name === name) return i;
   101→    }
   102→    return -1;
   103→  }
   104→
   105→  function declareLocal(name: string) {
   106→    scope().locals.push({ name, depth: scope().depth });
   107→  }
   108→
   109→  function resolveUpvalue(name: string): number {
   110→    if (scopes.length < 2) return -1;
   111→    const s = scope();
   112→    for (let i = 0; i < s.upvalues.length; i++) {
   113→      if (s.upvalues[i].name === name) return i;
   114→    }
   115→    const parent = scopes[scopes.length - 2];
   116→    for (let j = parent.locals.length - 1; j >= 0; j--) {
   117→      if (parent.locals[j].name === name) {
   118→        s.upvalues.push({ name, isLocal: true, index: j });
   119→        return s.upvalues.length - 1;
   120→      }
   121→    }
   122→    for (let j = 0; j < parent.upvalues.length; j++) {
   123→      if (parent.upvalues[j].name === name) {
   124→        s.upvalues.push({ name, isLocal: false, index: j });
   125→        return s.upvalues.length - 1;
   126→      }
   127→    }
   128→    return -1;
   129→  }
   130→
   131→  function compileStmts(stmts: Stmt[]) {
   132→    for (const s of stmts) compileStmt(s);
   133→  }
   134→
   135→  // Compile statements where the last expr must leave a value on the stack
   136→  function compileStmtsAsExpr(stmts: Stmt[]) {
   137→    for (let i = 0; i < stmts.length; i++) {
   138→      const s = stmts[i];
   139→      const isLast = i === stmts.length - 1;
   140→
   141→      if (isLast && s.kind === "expr") {
   142→        // Last statement is an expression: compile it but DON'T pop
   143→        compileExpr(s.expr);
   144→      } else if (isLast && s.kind === "if") {
   145→        // Last statement is an if-statement in expression context
   146→        // Both branches must leave values on the stack
   147→        compileExpr(s.cond);
   148→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   149→        compileStmtsAsExpr(s.then);
   150→        if (s.else) {
   151→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   152→          patchJump(jumpFalse);
   153→          compileStmtsAsExpr(s.else);
   154→          patchJump(jumpEnd);
   155→        } else {
   156→          // If-statement without else in expression context: push null as default
   157→          emitArg(Op.Const, addConst({ tag: "null" }));
   158→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   159→          patchJump(jumpFalse);
   160→          patchJump(jumpEnd);
   161→        }
   162→      } else {
   163→        compileStmt(s);
   164→      }
   165→    }
   166→  }
   167→
   168→  function compileStmt(s: Stmt) {
   169→    switch (s.kind) {
   170→      case "expr": compileExpr(s.expr); emit(Op.Pop); break;
   171→      case "let": {
   172→        if (scope().depth === 0) {
   173→          globals.add(s.name);
   174→          if (s.init) compileExpr(s.init); else emitArg(Op.Const, addConst({ tag: "null" }));
   175→          emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   176→        } else {
   177→          declareLocal(s.name);
   178→          if (s.init) compileExpr(s.init); else emitArg(Op.Const, addConst({ tag: "null" }));
   179→          // Store the value in the local variable slot
   180→          emitArg(Op.Store, scope().locals.length - 1);
   181→        }
   182→        break;
   183→      }
   184→      case "fn": {
   185→        if (scope().depth === 0) globals.add(s.name);
   186→        else declareLocal(s.name);
   187→        // Phase 6: Pass annotations to compileFnBody
   188→        compileFnBody(s.name, s.params, s.body, (s as any).annotations || []);
   189→        if (scope().depth === 0) {
   190→          emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   191→        }
   192→        break;
   193→      }
   194→      case "return": {
   195→        // Emit any pending finally blocks first
   196→        for (const fb of [...finallyStack].reverse()) {
   197→          compileStmts(fb);
   198→        }
   199→        if (s.value) compileExpr(s.value); else emitArg(Op.Const, addConst({ tag: "null" }));
   200→        emit(Op.Return);

