     1→// FreeLang v6: Parser (Pratt / Recursive Descent)
     2→
     3→import { Token, TokenType as T } from "./token";
     4→import { Expr, Stmt, Program, MatchArm } from "./ast";
     5→
     6→export function parse(tokens: Token[]): Program {
     7→  let pos = 0;
     8→
     9→  function peek(): Token { return tokens[pos]; }
    10→  function advance(): Token { return tokens[pos++]; }
    11→  function expect(type: T, msg?: string): Token {
    12→    const t = advance();
    13→    if (t.type !== type) throw new Error(msg ?? `Expected ${T[type]}, got ${T[t.type]} '${t.value}' at line ${t.line}`);
    14→    return t;
    15→  }
    16→  function match(type: T): boolean { if (peek().type === type) { advance(); return true; } return false; }
    17→  function at(type: T): boolean { return peek().type === type; }
    18→
